// ─────────────────────────────────────────────────────────────
function formaterDate(dateStr, langue) {
  if (!dateStr) return 'N/A';
  try {
    const date = new Date(dateStr);
    const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
    return date.toLocaleDateString(locale, { year: 'numeric', month: '2-digit', day: '2-digit' });
  } catch(e) { return dateStr; }
}

function formaterDateHeure(dateStr, langue) {
  if (!dateStr) return 'N/A';
  try {
    const date = new Date(dateStr);
    const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
    return date.toLocaleString(locale, { year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
  } catch(e) { return dateStr; }
}

function getEmoji(jours) {
  if (jours <= 2) return '🔴';
  if (jours === 3) return '🟠';
  if (jours === 4) return '🟡';
  if (jours <= 8) return '🔵';
  return '🟢';
}

// ─────────────────────────────────────────────────────────────
function genererMessagePrincipal(data) {
  const langue = data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;
  const dest = data.destinataire_principal;
  const stats = data.statistiques;
  const dossiers = data.dossiers;

  const sujet = (T.sujet_email[data.type_destinataire] || T.sujet_email.SALARIE)
              + ` - ${stats.total_dossiers} dossier(s)`;

  // ── Corps email ──
  let body = `${T.salutation} ${dest.prenom} ${dest.nom},\n\n`;
  body += `${T.introduction[data.type_destinataire]}\n\n`;
  body += `══════════════════════════════════════════════════════════\n`;
  body += `📊 ${T.section_stats}\n`;
  body += `══════════════════════════════════════════════════════════\n\n`;
  body += `${getEmoji(stats.jours_min)} Niveau d'escalade : ${data.niveau_escalade}\n`;
  body += `${T.total} : ${stats.total_dossiers}\n`;
  body += `${T.delai_min} : ${stats.jours_min} ${T.jours}\n`;
  body += `${T.delai_total} : ${stats.delai_total} ${T.jours}\n`;
  if (['DGA','BAALLAH'].includes(data.type_destinataire)) {
    body += `${T.seuil_dga} : ${stats.seuil_dga} ${T.jours}\n`;
  }
  body += `\n══════════════════════════════════════════════════════════\n`;
  body += `📋 ${T.section_dossiers}\n`;
  body += `══════════════════════════════════════════════════════════\n\n`;

  dossiers.forEach((dos, i) => {
    body += `${i + 1}. ${getEmoji(dos.jours_restants)} ${dos.num_dossier}\n`;
    body += `   📅 ${T.date_creation} : ${formaterDateHeure(dos.date_creation, langue)}\n`;
    if (dos.candidat && dos.candidat.nom) {
      body += `   👤 ${T.candidat} : ${dos.candidat.prenom} ${dos.candidat.nom} (${dos.candidat.code})\n`;
    }
    if (dos.poste_a_pourvoir) {
      body += `   💼 ${T.poste} : ${dos.poste_a_pourvoir}\n`;
    }
    body += `   ⏰ ${T.delai} : ${dos.jours_restants} ${T.jours} ${T.restant} (${T.limite} : ${formaterDate(dos.date_limite, langue)})\n`;
    if (dos.jours_restants <= 2) body += `   🚨 ${T.urgent}\n`;
    body += `\n`;
  });

  body += `══════════════════════════════════════════════════════════\n`;
  if (stats.jours_min <= 2) {
    body += `🚨 ${T.action_requise} : ${T.urgent}\n`;
  } else if (['DGA','BAALLAH'].includes(data.type_destinataire)) {
    body += `📌 ${T.instruction_dga}\n`;
  } else {
    body += `📌 ${T.instruction}\n`;
  }
  body += `══════════════════════════════════════════════════════════\n\n`;
  body += `${T.cordialement},\n\n${T.signature}\n\n`;
  body += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  body += `🤖 ${T.message_auto} - ${formaterDate(new Date().toISOString(), langue)}\n`;
  body += `${T.ne_pas_repondre}\n`;

  // ── Telegram ──
  let tg = `${getEmoji(stats.jours_min)} *${T.sujet_email[data.type_destinataire]}*\n`;
  tg += `━━━━━━━━━━━━━━━━━━━━━\n\n`;
  tg += `👤 *${dest.prenom} ${dest.nom}*\n\n`;
  tg += `📊 *${T.section_stats}*\n`;
  tg += `${T.total} : *${stats.total_dossiers}*\n`;
  tg += `${T.delai_min} : *${stats.jours_min} ${T.jours}*\n\n`;
  tg += `📋 *${T.section_dossiers}*\n\n`;

  dossiers.slice(0, 5).forEach((dos, i) => {
    tg += `${i + 1}. ${getEmoji(dos.jours_restants)} *${dos.num_dossier}*\n`;
    tg += `   📅 ${formaterDate(dos.date_creation, langue)}\n`;
    if (dos.candidat && dos.candidat.nom) {
      tg += `   👤 ${dos.candidat.prenom} ${dos.candidat.nom}\n`;
    }
    tg += `   ⏰ ${dos.jours_restants} ${T.jours} ${T.restant}\n\n`;
  });

  if (dossiers.length > 5) tg += `... et ${dossiers.length - 5} autre(s) dossier(s)\n\n`;
  if (stats.jours_min <= 2) tg += `🚨 *${T.urgent}*\n`;

  return {
    email:    { subject: sujet, body },
    telegram: { text: tg, parse_mode: 'Markdown' }
  };
}

